spec.expr:
sum(
  avg by (namespace, container) (
    rate(container_cpu_usage_seconds_total{container!="", container!="POD", node="$node"}[24h])
  ) <= 0.002
)

avg by (namespace, container) (
  avg_over_time(
    rate(container_cpu_usage_seconds_total{container!="", container!="POD", node="$node"}[$__rate_interval])
    [24h:5m]
  )
) > 0.002

sum by (namespace, container) (
  sum_over_time(
    rate(container_cpu_usage_seconds_total{container!="", container!="POD", node="$node"}[$__rate_interval])
    [24h:5m]
  ) / (24 * 60 / 5)
) > 0.003
